module top_module( clk, reset, d, q );input clk;
	input reset;
	input [5:0] d;
	output [5:0] q;
	reg [5:0] q;

	  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge reset or posedge dbg_halt) begin
		if (!reset) begin
			q <= 6'b0;
		end
		else begin
			q <= d;
		end
	end
endmodule
